// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	var csrfToken string

	// If a session cookie is provided, we can use its value as part of the state
	// to bind the OAuth flow to the current user's session and prevent CSRF attacks.
	if session != nil && session.Value != "" {
		csrfToken = session.Value
	} else {
		// Generate a new secure random CSRF token
		b := make([]byte, 32)
		if _, err := rand.Read(b); err != nil {
			return "", err
		}
		csrfToken = base64.URLEncoding.EncodeToString(b)

		// Set the generated CSRF token as a cookie so it can be verified in the callback handler
		cookie := &http.Cookie{
			Name:     "oauth_state",
			Value:    csrfToken,
			Path:     "/",
			MaxAge:   3600, // 1 hour
			HttpOnly: true,
			Secure:   r != nil && r.TLS != nil,
		}
		if w != nil {
			http.SetCookie(w, cookie)
		}
	}

	// Construct the state string.
	// We encode the redirectPath in base64 to safely embed it in the state parameter.
	// Format: "csrfToken:base64(redirectPath)" or just "csrfToken"
	state := csrfToken
	if redirectPath != "" {
		encodedPath := base64.URLEncoding.EncodeToString([]byte(redirectPath))
		state = csrfToken + ":" + encodedPath
	}

	// Generate and return the authorization URL
	authURL := OAuthConfig.AuthCodeURL(state)

	return authURL, nil
}

func main() {
	// Example usage demonstrating how to use GenerateAuthURL in an HTTP handler
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		// Example: user wants to be redirected to /dashboard after login
		redirectPath := r.URL.Query().Get("return_to")

		// Try to get existing session cookie
		session, _ := r.Cookie("session_id")

		url, err := GenerateAuthURL(redirectPath, session, w, r)
		if err != nil {
			http.Error(w, "Failed to generate authorization URL", http.StatusInternalServerError)
			return
		}

		// Redirect the user to the generated OAuth2 provider URL
		http.Redirect(w, r, url, http.StatusFound)
	})

